sql:
SELECT buffer_id, buffer_name
FROM data_buffers
WHERE is_active = 1 AND compression_ratio > 0.5;

SELECT cs.*, cp.* 
FROM compression_settings cs
INNER JOIN compression_performance cp ON cs.setting_id = cp.setting_id;

SELECT cp.setting_id, AVG(cp.compression_ratio) AS average_compression_ratio
FROM compression_performance AS cp
GROUP BY cp.setting_id;

SELECT db.buffer_id, db.buffer_name, dt.type_name AS data_type
FROM data_buffers db
INNER JOIN data_types dt ON db.data_type = dt.type_id;

SELECT buffer_name 
FROM data_buffers 
WHERE setting_id = 0 AND buffer_id = 1;

external_knowledge:
Buffer 1 refers to the primary data storage location for the application; 
The compression settings are crucial for optimizing data transfer and storage in the system; 
Each data buffer may have multiple compression settings associated with it.

sql:
SELECT db.buffer_id, db.buffer_name, cs.compression_level
FROM data_buffers AS db
JOIN compression_settings AS cs ON db.setting_id = cs.setting_id;

SELECT MIN(compression_ratio) 
FROM data_buffers
WHERE buffer_name = 'MyBuffer';

SELECT cs.*
FROM compression_settings cs
WHERE cs.setting_id = 1;
